var o = $json;
var prompt = 'Generate a capture plan for this federal opportunity. GDA (Georgetown Defense Analytics / Envision Innovative Solutions) is a mid-tier defense IT/engineering services firm.

';
prompt += 'Opportunity: ' + (o.opp_title || '') + '
';
prompt += 'Agency: ' + (o.agency || '') + '
';
prompt += 'Department: ' + (o.dept || '') + '
';
prompt += 'NAICS: ' + (o.naics_code || '') + '
';
prompt += 'Set-Aside: ' + (o.set_aside || 'None') + '
';
prompt += 'Value: $' + ((o.estimated_value || 0) / 1000000).toFixed(1) + 'M
';
prompt += 'Deadline: ' + (o.response_deadline || 'TBD') + '
';
prompt += 'GDA Score: ' + (o.gda_score || 0) + '
';
prompt += 'AI Analysis: ' + (o.ai_analysis || '') + '
';
prompt += 'Assigned OU: ' + (o.assigned_ou || 'TBD') + '

';
prompt += 'Respond ONLY with JSON (no markdown):
{
';
prompt += '  "opportunity_name": "short name",
';
prompt += '  "pwin": 10-90,
';
prompt += '  "capture_stage": "Interest|Pursue|Qualify|Proposal",
';
prompt += '  "allocated_revenue": estimated annual revenue in millions,
';
prompt += '  "win_strategy": "2-3 sentences on how GDA wins",
';
prompt += '  "key_risks": ["risk 1", "risk 2"],
';
prompt += '  "next_actions": ["action 1", "action 2", "action 3"],
';
prompt += '  "teaming_strategy": "prime/sub/JV approach",
';
prompt += '  "incumbent": "known incumbent or Unknown",
';
prompt += '  "discriminators": ["disc 1", "disc 2"]
}';

return [{ json: { opp_id: o.id, opp_title: o.opp_title, prompt: prompt } }];

const input = $input.first().json;
const oppId = $('Build Prompt').first().json.opp_id;
const oppTitle = $('Build Prompt').first().json.opp_title;

let text = '';
try {
  if (input.content && input.content[0]) text = input.content[0].text || '';
  else text = JSON.stringify(input);
} catch(e) { text = ''; }

let parsed = {};
try {
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1) parsed = JSON.parse(text.substring(start, end + 1));
} catch(e) { parsed = { error: 'parse failed', raw: text.substring(0, 300) }; }

return [{ json: {
  opp_id: oppId,
  opp_title: oppTitle,
  opportunity_name: parsed.opportunity_name || oppTitle,
  pwin: parsed.pwin || 10,
  capture_stage: parsed.capture_stage || 'Interest',
  allocated_revenue: parsed.allocated_revenue || 0,
  win_strategy: parsed.win_strategy || '',
  key_risks: JSON.stringify(parsed.key_risks || []),
  next_actions: JSON.stringify(parsed.next_actions || []),
  teaming_strategy: parsed.teaming_strategy || '',
  incumbent: parsed.incumbent || 'Unknown',
  discriminators: JSON.stringify(parsed.discriminators || [])
}}];
